import React, { Fragment, useState, useEffect } from 'react';
import { Card, CardHeader, CardBody, Col, Row } from 'reactstrap';
import DataTable from 'react-data-table-component';
import { H3, Breadcrumbs, Btn } from '../../AbstractElements';
import { useNavigate } from 'react-router-dom';
import { getClientUrlDataToken } from '../../Utils/restUtils';
import { ExpenseSummaryRep, ExpenseSummaryList, Vendor, Header, Year, Filters, Search } from '../../Constant';
import SearchList from '../../CommonElements/Search';
import { expenceSummary, expenceSummaryRole, selectHeaders, selectHeadersRole, selectVendor, selectVendorRole, viewPackageReport, viewPackageReportRole } from '../../CommonUrl';
import { useSelector } from 'react-redux';
import { ExpenseSummaryColumns } from './Header/ReportTableHeader';
import HandleApiError from '../Common/ErrorImport/ErrorImport';
import Transparentspinner from '../Common/Loader/Transparentspinner';
import { getYearOption } from './DropDownOption';

const ExpenseSummary = () => {
    const authState = useSelector((state) => state.auth);
    const searchParams = location.search;
    const params = new URLSearchParams(searchParams);

    const [customerLists, setCustomerList] = useState([]);
    const [resetPaginationToggle, setResetPaginationToggle] = useState(false);
    const [loading, setLoading] = useState(false);
    const [totalRows, setTotalRows] = useState(0);
    const [perPage, setPerPage] = useState(10);
    const [currentPage, setCurrentPage] = useState(1);
    const [apiHeader, setapiHeader] = useState([]);
    const [filters, setFilters] = useState({
        year: params.get('year') || new Date().getFullYear(),
        headerId: params.get('headerId') || '',
        search: params?.get('search') || ''
    })

    const navigate = useNavigate();


    //header dropdown data fetch
    const headerData = async () => {
        const data = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ? selectHeaders : selectHeadersRole);
        if (data.status === true) {
            setapiHeader(data.data);
        } else {
            HandleApiError(navigate, data.status);
        }
    };

    //fetch expence summary table data
    const fetchExpenseSummary = async (page, size = perPage) => {
        setLoading(true);
        const response = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ? expenceSummary + `?page=${page}&page_length=${size}&year=${filters?.year}&header_id=${filters?.headerId}&search=${filters?.search}` : expenceSummaryRole +
            `?page=${page}&page_length=${size}&year=${filters?.year}&header_id=${filters?.headerId}&search=${filters?.search}`);
        if (response.status === true) {
            setResetPaginationToggle(!resetPaginationToggle);
            setLoading(true);
            const valuePackages = response.data
            setCustomerList(response?.data?.map((item, index) => {
                return {
                    Si: index + 1,
                    Category: item.name,
                    January: item?.Jan,
                    February: item?.Feb,
                    March: item?.Mar,
                    April: item.Apr,
                    May: item.May,
                    June: item.Jun,
                    July: item.Jul,
                    August: item.Aug,
                    September: item.Sep,
                    October: item.Oct,
                    November: item.Nov,
                    December: item.Dec
                }
            }
            ))
            setLoading(false);
            setTotalRows(response.data.total);
            setLoading(false);

        } else if (response.status >= 400 && response.status <= 405) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page1`);
        } else if (response.status >= 500 && response.status <= 505) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
        }
        else {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page3`);
        }
        setLoading(false);
    };


    //pagination
    const handlePageChange = page => {
        fetchExpenseSummary(page);
        setCurrentPage(page);
    };
    const handlePerRowsChange = async (newPerPage, page) => {
        fetchExpenseSummary(page, newPerPage);
        setPerPage(newPerPage);
    };

    //filter handling
    const handleFilter = (data) => {
        const year = filters?.year || '';
        const headerId = filters?.headerId || '';
        const search = filters?.search || '';

        setFilters({
            year,
            headerId,
            search
        });


        const queryParams = new URLSearchParams({
            year: year,
            headerId: headerId,
            search: search
        }).toString();

        navigate(`/report/expense-summary?${queryParams}`);
    }
    



    useEffect(() => {
        fetchExpenseSummary(1);
        headerData()
    }, []);

    return (
        <Fragment>
            {
                loading && <Transparentspinner />
            }
            <Breadcrumbs mainTitle={ExpenseSummaryRep} parent="Reports" title={ExpenseSummaryRep} />
            <Card>
                <CardHeader>
                    <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                        <H3>{ExpenseSummaryList}</H3>
                    </div>
                </CardHeader>
                <Row className='ps-3 gap-sm-3 gap-md-2 filterGap'>
                    <Col sm="12" md="2" className="form-element">
                        <input value={filters?.search} onChange={(e) => { setFilters({ ...filters, search: e.target.value }) }} className="form-control" placeholder={Search} type="text"
                        />

                    </Col>
                    <Col sm="12" md="3" className="form-element">
                        <select className="form-select" value={filters?.year} onChange={(e) => setFilters({ ...filters, year: e.target.value })} >
                            {/* <option key='vendor' value="">{Year}</option> */}
                            {getYearOption().map((values, index) => (
                                <option key={values} value={values}>{values}</option>
                            ))}
                        </select>
                    </Col>
                    <Col sm="12" md="3" className="form-element">
                        <select className="form-select" value={filters?.headerId} onChange={(e) => setFilters({ ...filters, headerId: e.target.value })}  >
                            <option key='header' value="">{Header}</option>
                            {apiHeader.map((values, index) => (
                                <option key={values.id} value={values.id}>{values.title}</option>
                            ))}
                        </select>
                    </Col>
                    <Col sm="12" md="2" className="">
                        <button className='btn btn-primary' onClick={() => { handleFilter() }} type="button">{Filters}</button>
                    </Col>
                </Row>
                <CardBody>
                    <div className="order-history table-responsive">
                        <DataTable
                            columns={ExpenseSummaryColumns}
                            data={customerLists}
                            // progressPending={loading}
                            pagination
                            paginationServer
                            defaultSortAsc
                            paginationRowsPerPageOptions={[10, 25, 50, 100]}
                            paginationTotalRows={totalRows}
                            paginationDefaultPage={currentPage}
                            onChangeRowsPerPage={handlePerRowsChange}
                            onChangePage={handlePageChange}
                            fixedHeader
                        />
                    </div>
                </CardBody>
            </Card>
        </Fragment>
    );
};

export default ExpenseSummary;